import itertools
import math

def pick_coins_naive(p_values):
    """Naive method: Try all possible sets of n coins and return the one with highest probability."""
    n = len(p_values) // 2
    max_probability = 0
    best_set = []
    for coin_set in itertools.combinations(p_values, n):
        probability = 0
        for i in range(n):
            probability += math.comb(n, i) * coin_set[i] ** i * (1 - coin_set[i]) ** (n - i)
        if probability > max_probability:
            max_probability = probability
            best_set = coin_set
    return best_set

def pick_coins_dp(p_values):
    """Dynamic programming method: Build a table to efficiently compute the probabilities."""
    n = len(p_values) // 2
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1
    for i in range(1, n + 1):
        for j in range(i, n + 1):
            dp[i][j] = dp[i-1][j-1] * p_values[i-1] + dp[i-1][j] * (1 - p_values[i-1])
    max_probability = 0
    best_set = []
    for i in range(n + 1):
        if dp[n][i] > max_probability:
            max_probability = dp[n][i]
            best_set = p_values[:i] + p_values[i+1:]
    return best_set

