def find_best_set_brute_force(p_values, n):
    """
    Find the best set of coins using brute force approach.
    """
    max_probability = 0
    best_set = None
    for coin_set in itertools.combinations(p_values, n):
        probability = calculate_probability(coin_set, n)
        if probability > max_probability:
            max_probability = probability
            best_set = coin_set
    return best_set

def calculate_probability(p_values, n):
    """
    Calculate the probability of getting n heads when tossing the coins.
    """
    probability = 1
    for p in p_values:
        probability *= p
    for p in [1 - p for p in p_values]:
        probability *= p
    return probability

def find_best_set_dynamic_programming(p_values, n):
    """
    Find the best set of coins using dynamic programming approach.
    """
    p_values = sorted(p_values, reverse=True)
    dp = [[0] * (n + 1) for _ in range(len(p_values) + 1)]
    for i in range(1, len(p_values) + 1):
        for j in range(1, n + 1):
            if j > i:
                dp[i][j] = dp[i - 1][j]
            else:
                dp[i][j] = max(dp[i - 1][j], (1 - p_values[i - 1]) * dp[i - 1][j - 1] + p_values[i - 1] * dp[i - 1][j])
    best_set = []
    i, j = len(p_values), n
    while i > 0 and j > 0:
        if dp[i][j] != dp[i - 1][j]:
            best_set.append(p_values[i - 1])
            j -= 1
        i -= 1
    return tuple(best_set)

